  ///    bit  3: UNDERLINE         bit 11: DOUBLE_UNDERLINE
  ///    bit  4: WRAPLINE          bit 12: UNDERCURL
  ///    bit  5: WIDE_CHAR         bit 13: DOTTED_UNDERLINE
